// Validate response
const items = $json.products;
if (!items || !Array.isArray(items)) {
  throw new Error('Invalid API response: products array missing');
}
// Normalize each product
return items.map(p => ({
  json: {
    external_product_id: String(p.id),
    title: p.title,
    description: p.description,
    category: p.category,
    image_url: p.thumbnail,
    current_price: p.price,
    currency: 'USD',
    competitor_name: 'DemoMart'
  }
}));

const products = $json.products || [];
return products.map(p => ({ json: {
  external_product_id: String(p.id),
  title: p.title,
  description: p.description,
  category: p.category,
  image_url: p.thumbnail,
  current_price: p.price,
  currency: 'USD',
  competitor_name: 'DemoMart'
}}));

// Prepare data for price history using the returned product ID
return [{
  json: {
    product_id: $json.id,
    price: $json.current_price,
    currency: $json.currency,
    observed_at: new Date().toISOString()
  }
}];

// Collect all product IDs that were just processed to trigger enrichment
const productIds = $input.all().map(item => item.json.product_id);
return [{ json: { productIds } }];

// If any error occurs, log it (this node would be connected to error output)
console.error('Workflow failed:', $json.error);
return [];
